#include <pthread.h>
#include <stdio.h>
#include <stdlib.h>

#define NUM_THREADS 3

typedef struct {
    int thread_id;
    int priority;
    int burst_time;
} ThreadData;

void* thread_function(void* arg) {
    ThreadData* data = (ThreadData*)arg;
    printf("Thread %d (Priority: %d) started\n", 
           data->thread_id, data->priority);
    sleep(data->burst_time);
    printf("Thread %d finished\n", data->thread_id);
    return NULL;
}

int main() {
    pthread_t threads[NUM_THREADS];
    ThreadData thread_data[NUM_THREADS];

    // Initialize threads with different priorities
    for(int i = 0; i < NUM_THREADS; i++) {
        thread_data[i].thread_id = i + 1;
        thread_data[i].priority = (i == 0) ? 3 : (i == 1) ? 1 : 2;
        thread_data[i].burst_time = 2;
    }

    // Create threads - in practice, scheduler uses priority
    for(int i = 0; i < NUM_THREADS; i++) {
        pthread_create(&threads[i], NULL, thread_function, &thread_data[i]);
    }

    // Wait for all threads
    for(int i = 0; i < NUM_THREADS; i++) {
        pthread_join(threads[i], NULL);
    }

    return 0;
}

import java.util.LinkedList;
import java.util.Queue;

class Thread implements Comparable<Thread> {
    int id;
    int burstTime;
    int remainingTime;

    public Thread(int id, int burstTime) {
        this.id = id;
        this.burstTime = burstTime;
        this.remainingTime = burstTime;
    }

    public int compareTo(Thread t) {
        return this.id - t.id;
    }
}

public class RoundRobinScheduler {
    private static final int TIME_QUANTUM = 4;

    public static void schedule(Queue<Thread> readyQueue) {
        int currentTime = 0;
        int completed = 0;
        int totalThreads = readyQueue.size();

        while(completed < totalThreads) {
            Thread thread = readyQueue.poll();

            if(thread == null) break;

            if(thread.remainingTime <= TIME_QUANTUM) {
                // Thread completes
                currentTime += thread.remainingTime;
                System.out.println("Thread " + thread.id + 
                    " completed at time " + currentTime);
                completed++;
            } else {
                // Time quantum expires
                currentTime += TIME_QUANTUM;
                thread.remainingTime -= TIME_QUANTUM;
                System.out.println("Thread " + thread.id + 
                    " quantum expired, remaining: " + 
                    thread.remainingTime);
                readyQueue.add(thread);
            }
        }
    }

    public static void main(String[] args) {
        Queue<Thread> readyQueue = new LinkedList<>();
        readyQueue.add(new Thread(1, 10));
        readyQueue.add(new Thread(2, 5));
        readyQueue.add(new Thread(3, 8));

        schedule(readyQueue);
    }
}
